-- Seed Inventory Database Schema and Initial Data
-- Created: 2026-04-08
-- Sourced from Premier Seeds Direct (www.premierseedsdirect.com)

CREATE TABLE IF NOT EXISTS seed_inventory (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL,
  variety TEXT,
  type TEXT,
  quantity INTEGER,
  supplier TEXT,
  purchase_year INTEGER,
  sow_by_year INTEGER,
  notes TEXT,
  purchase_link TEXT,
  days_to_germinate TEXT,
  optimum_soil_temp TEXT,
  optimum_soil_type TEXT,
  plant_height TEXT,
  light_requirements TEXT,
  growing_instructions TEXT,
  sow_indoors_start TEXT,
  sow_indoors_end TEXT,
  sow_outdoors_start TEXT,
  sow_outdoors_end TEXT,
  plant_out_start TEXT,
  plant_out_end TEXT,
  harvest_start TEXT,
  harvest_end TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);

-- Clear existing data
DELETE FROM seed_inventory;

