INSERT INTO seed_inventory (name, variety, type, quantity, supplier, purchase_year, sow_by_year, notes, purchase_link, days_to_germinate, optimum_soil_temp, optimum_soil_type, plant_height, light_requirements, growing_instructions, sow_indoors_start, sow_indoors_end, sow_outdoors_start, sow_outdoors_end, plant_out_start, plant_out_end, harvest_start, harvest_end) VALUES
('Lettuce', 'Gourmet Looseleaf Cutting Mix', 'vegetable', NULL, 'Premier Seeds Direct', 2026, 2030, 'Fast-growing blend of 6 looseleaf varieties', 'https://premierseedsdirect.com/product/lettuce-gourmet-looseleaf-cutting-mix/', '7-14 days', NULL, NULL, NULL, NULL, 'Sow directly in prepared soil 1.5cm deep in shallow rows. Thin to 5cm apart. Harvest baby leaves around 20 days. Sow every 4 weeks for continuous supply. Water regularly to prevent bolting.', NULL, NULL, '03-01', '08-31', NULL, NULL, '04-20', '09-20'),
('Lettuce', 'Crispy Mix', 'vegetable', NULL, 'Premier Seeds Direct', 2026, 2030, 'Blend of crisp-leaf varieties: Sulfita, Nadita, Crispita, Crackita with green and red leaves', 'https://premierseedsdirect.com/product/lettuce-crispy-mix/', '7-14 days', NULL, NULL, NULL, NULL, 'Sow directly outside March-August in prepared soil 1.5cm deep in shallow rows. Germination 7-14 days. Thin to 5cm apart. Harvest baby leaves in around 20 days. Water regularly to prevent bolting.', NULL, NULL, '03-01', '08-31', NULL, NULL, '04-20', '09-20'),
('Mustard', 'Salad Leaf Tasty Mix', 'vegetable', 1000, 'Premier Seeds Direct', 2026, 2029, 'Vibrant mix of mustard varieties including Pizzo, Red Lace, Red Zest, Red Lion, Green Frills', 'https://premierseedsdirect.com/product/mustard-salad-leaf-tasty-mix/', NULL, NULL, NULL, NULL, NULL, 'Sow indoors all year round or directly outside May-September. Sow on moist compost and lightly cover. Take leaves when thinning for baby leaves. Harvest when 12-15cm. Baby leaves around 20 days, mature plants 35 days.', '01-01', '12-31', '05-01', '09-30', NULL, NULL, '06-20', '10-15'),
('Carrot', 'Resistafly', 'vegetable', 1300, 'Premier Seeds Direct', 2026, 2028, 'British bred F1 Nantes hybrid with good carrot root fly resistance. Cylindrical roots with excellent taste.', 'https://premierseedsdirect.com/product/carrot-resistafly/', NULL, NULL, NULL, NULL, NULL, 'Sow directly in ground 2cm deep, 15cm apart. Start sowing 2 weeks before last frost. Make successive plantings every 3 weeks. A second crop can be planted late summer/early autumn.', NULL, NULL, '03-15', '08-31', NULL, NULL, '06-01', '10-31'),
('Carrot', 'Sweet Candle F1', 'vegetable', 220, 'Premier Seeds Direct', 2026, 2028, 'Deep orange Nantes type with exceptional taste and high yields. Allotment growers favourite.', 'https://premierseedsdirect.com/product/carrot-sweet-candle-f1/?attribute_pa_seed-count=220', NULL, NULL, 'Well-prepared, fine texture 15-25cm deep', NULL, NULL, 'Sow 1cm deep, 30-40cm between rows as soon as danger of frost passes. Thin to 16-20 per 30cm for small carrots, 6-10 for mid-season. Keep weeded and watered. Push soil over exposed roots to prevent green shoulder.', NULL, NULL, '03-15', '07-31', NULL, NULL, '06-01', '10-31'),
('Carrot', 'Rainbow Mix', 'vegetable', 1500, 'Premier Seeds Direct', 2026, 2028, 'Purple, Yellow, White, Red varieties (Cosmic Purple, Solar Yellow, Lunar White, Atomic Red) with different flavours. Mixed seed packet of equal quantities.', 'https://premierseedsdirect.com/product/carrot-rainbow-mix/?attribute_pa_seed-count=1500', NULL, NULL, 'Light, stone-free soil', NULL, NULL, 'Dig or till bed deeply on dry soil. Work to fine texture 15-25cm deep. Avoid freshly-manured soil. Sow 1cm deep, 30-40cm between rows as soon as danger of hard frost passes. Thin to 16-20 per 30cm for fresh eating, 6-10 for mid-season crops depending on size wanted.', NULL, NULL, '03-15', '07-31', NULL, NULL, '06-01', '10-31'),
('Pepper', 'Habanero Chocolate', 'vegetable', 15, 'Premier Seeds Direct', 2026, 2028, 'Lantern-shaped fruits in rich, deep brown. Intense heat (300,000–575,000 Scoville) and smoky, earthy flavour. Plants 3ft. Can be perennial, overwinter indoors for early next crop.', 'https://premierseedsdirect.com/product/pepper-habanero-chocolate/?attribute_pa_seed-count=15-seeds', '10-21 days', '22-24°C', NULL, '90cm', 'Heated propagator essential', 'Sow on moist soil, lightly cover. Place in bright location. Best at 22-24°C constant temperature. Germination 10-21 days. Transplant to individual pots when true leaves develop. Plant 10-12cm high at 1cm below soil surface. Support stem. Water regularly, feed weekly.', '01-15', '03-15', NULL, NULL, '05-01', '06-30', '08-01', '10-31'),
('Pepper', 'Habanero Orange', 'vegetable', 15, 'Premier Seeds Direct', 2026, 2028, 'Classic hot chilli with small lantern-shaped orange fruits. Fruitier flavour than chocolate variety, still intense heat.', 'https://premierseedsdirect.com/product/pepper-habanero-orange/?attribute_pa_seed-count=15-seeds', '10-21 days', '21°C', NULL, NULL, 'Greenhouse/Conservatory', 'Sow 1/4" deep in 3in pots with quality seed compost. Keep moist. Seedlings emerge 10-21 days at 70°F+. Transplant when 2+ pairs of leaves. Plant 4-5 inches high, 18" apart, 1/2" below soil. Keep moist, feed with tomato fertiliser when flowering. Harvest full-size and full colour.', '01-15', '03-15', NULL, NULL, '05-01', '06-30', '08-01', '10-31'),
('Tomato', 'Sweet Million F1', 'vegetable', 20, 'Premier Seeds Direct', 2026, 2030, 'Heavy F1 cherry variety producing huge amounts of extra sweet bright red fruits. Robust, performs well under glass or outdoors in sunny sheltered location.', 'https://premierseedsdirect.com/product/tomato-cherry-sweet-million-f1/?attribute_pa_seed-count=20', '6-14 days', '65-75°F', NULL, '2m', 'Sunny, sheltered', 'Sow spring 1/16 inch deep. Germination 6-14 days at 65-75°F. Transplant when 8 inches tall. Plant 18 inches apart in warm, sunny, moist soil. Support stem.', '02-01', '03-15', NULL, NULL, '05-01', '06-15', '07-01', '09-30'),
('Tomato', 'Sweet Aperitif', 'vegetable', 20, 'Premier Seeds Direct', 2026, 2030, 'High yielding cherry variety delivering abundance of 10-15g bright red small fruits with exceptional refreshing tang. High sugar and acid levels.', 'https://premierseedsdirect.com/product/tomato-cherry-sweet-aperitif', '6-14 days', '65-75°F', NULL, NULL, 'Sunny location', 'Sow in spring 1/16 inch deep. Germination 6-14 days at 65-75°F. Transplant when large enough to handle into 3 inch pots. Grow on under cooler conditions. When 8 inches tall, plant in greenhouse or gradually acclimatise to outdoors. Plant 18 inches apart in warm sunny spot in moist fertile well drained soil.', '02-01', '03-15', NULL, NULL, '05-01', '06-15', '07-01', '09-30'),
('Tomato', 'Nagina F1 Blight Resistant', 'vegetable', 10, 'Premier Seeds Direct', 2026, 2030, 'First truly blight-resistant plum tomato variety producing excellent crops of small 65gm fruits with rich, full flavour. Ideal for greenhouse and outdoor growing.', 'https://premierseedsdirect.com/product/tomato-plum-nagina-f1', '6-14 days', '65-75°F', NULL, NULL, 'Sunny location', 'Sow in spring 1/16 inch deep in fine seed grade compost. Germination 6-14 days at 65-75°F. Transplant when large enough into 3 inch pots. Grow on under cooler conditions. When 8 inches tall, plant in greenhouse or gradually acclimatise to outdoors. Plant 18 inches apart in warm sunny spot in moist fertile well drained soil.', '02-01', '03-15', NULL, NULL, '05-01', '06-15', '07-01', '09-30'),
('Tomato', 'Riesling F1', 'vegetable', 10, 'Premier Seeds Direct', 2026, 2030, 'Outstanding indeterminate mini-plum variety with huge trusses of bright red, dense firm sweet fruits. RHS Award of Garden Merit. Best under glass.', 'https://premierseedsdirect.com/product/tomato-rielsing-f1', '6-14 days', '65-75°F', NULL, NULL, 'Greenhouse/Under glass', 'Sow in spring 1/16 inch deep in fine seed grade compost. Germination 6-14 days at 65-75°F. Transplant when large enough into 3 inch pots. Grow on under cooler conditions. When 8 inches tall, plant in greenhouse or gradually acclimatise to outdoors. Plant 18 inches apart in warm sheltered sunny spot in moist fertile well drained soil. Will need support.', '02-01', '03-15', NULL, NULL, '05-01', '06-15', '07-01', '09-30'),
('Tomato', 'Supersweet 100 F1', 'vegetable', 10, 'Premier Seeds Direct', 2026, 2030, 'Medium-early cherry variety. Heavy yields of exceptionally sweet small round fruits (20g each). Indeterminate. Long trailing trusses with up to 100 tomatoes on single truss under ideal conditions.', 'https://premierseedsdirect.com/product/tomato-supersweet-100-f1/?attribute_pa_seed-count=10-seeds', '7-14 days', '20-24°C', NULL, NULL, 'Bright location', 'Sow on moist soil, lightly cover. Compress gently, place in bright location. Heated propagator at 20-24°C. Germination 7-14 days. Transplant seedlings with 6 sets of leaves. Support stem. Water regularly, feed weekly.', '02-01', '03-15', NULL, NULL, '05-01', '06-15', '07-01', '09-30'),
('Tomato', 'Romello F1', 'vegetable', 6, 'Premier Seeds Direct', 2026, 2030, 'Outdoor cherry plum variety with late blight resistance and sweet flavourful fruit. Long clusters of small juicy tomatoes with crack resistance. Compact bush ideal for hanging baskets and containers.', 'https://premierseedsdirect.com/product/tomato-romello-f1/?attribute_pa_seed-count=6-seeds', '7-14 days', '20-24°C', NULL, NULL, 'Bright location', 'Sow on moist soil, lightly cover. Compress gently, place in bright location. Heated propagator at 20-24°C. Germination 7-14 days. Transplant when true leaves develop. If planting in hanging basket, one per basket. Water regularly, feed weekly.', '02-01', '03-15', NULL, NULL, '05-01', '06-15', '07-01', '09-30'),
('Cucumber', 'Gherkin Anulka F1', 'vegetable', NULL, 'Premier Seeds Direct', 2026, 2030, 'F1 Hybrid gherkin cucumber suitable for outdoor and glass production. Small light green ribbed fruits with few warts, perfect for pickles and preserves. Productive with high resistance to downy mildew and green mottle mosaic virus. Self-pollinating. Needs daily picking in main season.', 'https://premierseedsdirect.com/product/cucumber-gherkin-anulka-f1/?attribute_pa_seed-count=4gm', NULL, NULL, NULL, NULL, 'Warm location', 'Sow under cover mid-spring, 3-4 seeds 1 inch deep in 3in pot, thin to 1-2 best plants. Transplant no later than 3 weeks after seeding. Cucumbers need warmth, germinate best in summer, avoid planting too early unless protected with fleece. Keep evenly moist to prevent bitterness. Can train on trellis or let roam. Cut regularly for continuous production.', '03-15', '04-30', NULL, NULL, '05-15', '06-15', '06-15', '08-31'),
('Pepper', 'Jalapeno M Hot Chilli', 'vegetable', 25, 'Premier Seeds Direct', 2026, 2028, 'Medium to tall variety producing heavy crops of pungent thick-walled dark green peppers ripening to deep red. Fruit 8cm x 2cm with blunt end. 2,000–5,000 SHU. Plant height 60-90cm. Pick green or leave to mature for drying.', 'https://premierseedsdirect.com/product/hot-chilli-pepper-jalapeno-m/?attribute_pa_seed-count=25-seeds', '10-21 days', '21°C', NULL, '75cm', 'Greenhouse/Conservatory', 'Sow 1/4" deep in 3in pots with seed compost, keep moist. Emerge 10-21 days at 70°F+. Transplant to individual containers at 2+ pairs of leaves. Plant 4-5 inches high, 18" apart, 1/2" below soil. Keep moist, feed with tomato fertiliser when flowering. Harvest full-size and full colour.', '01-15', '03-15', NULL, NULL, '05-01', '06-30', '08-01', '10-31'),
('Pepper', 'Large Red Cherry Hot', 'vegetable', 75, 'Premier Seeds Direct', 2026, 2028, 'Productive variety with round cherry-sized fruits ripening from green to glossy vibrant red. Thick-walled, full of flavour with spicy kick. Ideal for pickling. Scoville: 2,500–5,000 units.', 'https://premierseedsdirect.com/product/hot-chilli-pepper-large-red-cherry', '7-14 days', '22-24°C', NULL, NULL, 'Heated propagator essential', 'Sow on moist soil, lightly cover. Compress soil gently, place in bright location. Best in heated propagator at 22-24°C. Germination 7-14 days. Transplant to individual pots when true leaves develop. Support stem may be required. Water regularly, feed weekly with all-purpose plant feed.', '01-15', '03-15', NULL, NULL, '05-01', '06-30', '08-01', '10-31'),
('Nemesia', 'Orange Prince', 'flower', 1200, 'Yorkshire Seeds', 2025, 2028, 'Annual flower with clustered blooms in vibrant orange. Nemesia strumosa variety produces abundant flowers throughout summer.', 'https://yorkshire-seeds.co.uk/products/1200x-nemesia-orange-prince-seeds-nemesia-strumosa-annual-flower-clusters-d169', '7-14 days', '15-20°C', NULL, '30-45cm', 'Full sun to partial shade', 'Sow indoors in early spring on seed compost, do not cover. Germination 7-14 days. Prick out into trays when large enough. Harden off and plant out after last frost. Space 15cm apart. Water regularly and deadhead to prolong flowering.', '02-01', '03-15', NULL, NULL, '04-15', '05-31', '05-01', '09-30'),
('Marigold', 'French Dwarf Boy Spry', 'flower', 300, 'Yorkshire Seeds', 2025, 2028, 'Dwarf French marigold producing compact plants with abundant golden flowers. Tagetes variety ideal for borders and containers.', 'https://yorkshire-seeds.co.uk/products/300x-french-marigold-dwarf-tagetes-boy-spry-flower-b106', '7-10 days', '18-21°C', NULL, '30-35cm', 'Full sun', 'Sow indoors in spring on surface of seed compost, do not cover. Germination 7-10 days at 18-21°C. Prick out when large enough. Harden off and plant out after last frost, 30cm apart. Water moderately. Deadhead regularly to encourage more flowers.', '03-01', '04-30', NULL, NULL, '05-01', '05-31', '05-01', '10-31'),
('Marigold', 'Starfire Mix', 'flower', 350, 'Yorkshire Seeds', 2025, 2028, 'Mexican marigold Tagetes tenuifolia mix with colours including orange, red and yellow. Delicate foliage and prolific flowering.', 'https://yorkshire-seeds.co.uk/products/350x-marigold-starfire-mix-seeds-tagetes-tenuifolia-mexican-marigold-flower-a55', '7-10 days', '18-21°C', NULL, '25-30cm', 'Full sun', 'Sow indoors in spring on seed compost surface without covering. Germination 7-10 days at 18-21°C. Prick out when large enough to handle. Harden off and plant out after last frost, 20cm apart. Drought tolerant once established. Deadhead for prolonged flowering.', '03-01', '04-30', NULL, NULL, '05-01', '05-31', '05-01', '10-31'),
('Marigold', 'African Tall Sierra', 'flower', 350, 'Yorkshire Seeds', 2025, 2028, 'African marigold producing huge orange flowers on tall plants. Impressive height and bold colour for borders.', 'https://yorkshire-seeds.co.uk/products/african-marigold-tall-sierra-350x-seeds-huge-orange-flowers', '7-10 days', '18-21°C', NULL, '60-90cm', 'Full sun', 'Sow indoors in spring on seed compost surface. Germination 7-10 days at 18-21°C. Prick out when large enough. Harden off and plant out after last frost, 45-60cm apart. Tall varieties may need support. Deadhead spent flowers regularly.', '03-01', '04-30', NULL, NULL, '05-01', '05-31', '05-01', '10-31'),
('Parsnip', 'White Gem', 'vegetable', 350, 'Yorkshire Seeds', 2025, 2027, 'White-skinned parsnip producing long, uniform roots with excellent flavour. Stores well over winter.', 'https://yorkshire-seeds.co.uk/products/parsnip-white-gem-fresh-vegetable-350x-seeds', '15-20 days', '12-18°C', 'Deep, stone-free soil', '25cm', 'Full sun', 'Sow direct in spring as soon as soil can be worked, 1.5cm deep in drills 30cm apart. Thin seedlings to 15cm when large enough. Keep well watered. Harvest from October through to March. Can be left in ground for extended storage.', NULL, NULL, '02-15', '03-31', NULL, NULL, '10-01', '03-31'),
('Onion', 'Jumbo Sweet Spanish', 'vegetable', 300, 'Yorkshire Seeds', 2025, 2027, 'Large Spanish onion variety with mild, sweet flavour. Excellent for fresh eating and stores moderately well.', 'https://yorkshire-seeds.co.uk/products/jumbo-sweet-spanish-onion-300x-seeds-vegetable', '7-14 days', '16-21°C', NULL, '10cm', 'Full sun', 'Sow indoors in late winter into seed compost. Germination 7-14 days. When 10cm tall, transplant outdoors 15cm apart in rows 30cm apart. Keep well watered during growing season. Harvest when foliage dies down, typically July/August. Cure in warm dry place before storing.', '01-15', '02-28', NULL, NULL, '04-01', '05-15', '07-01', '08-31'),
('Leek', 'Bulgarian Giant Winter Hardy', 'vegetable', 100, 'Yorkshire Seeds', 2025, 2027, 'Winter hardy leek producing tall white stems. Excellent for autumn and winter harvesting. Very cold tolerant.', 'https://yorkshire-seeds.co.uk/products/bulgarian-giant-leek-winter-hardy-100x-seeds-vegetable', '12-18 days', '15-18°C', NULL, '30-40cm', 'Full sun to partial shade', 'Sow indoors in late winter into seed compost. Germination 12-18 days. Plant out seedlings when 15-20cm tall into prepared soil, 15cm apart with 30cm between rows. Gradually earth up around stems as plants grow. Harvest from October through to March by digging from ground.', '01-01', '03-15', NULL, NULL, '04-15', '06-30', '10-01', '03-31'),
('Rhubarb', 'Champagne Spring & Autumn', 'vegetable', 30, 'Yorkshire Seeds', 2025, 2029, 'Spring and autumn rhubarb variety producing tender pink stems with excellent flavour. Perennial producing for many years.', 'https://yorkshire-seeds.co.uk/products/champagne-rhubarb-spring-autumn-seeds-30x-seeds-vegetable', '14-21 days', '15-18°C', NULL, '60-90cm', 'Full sun to partial shade', 'Soak seed overnight. Sow into pots of seed compost indoors. Germination 14-21 days. Grow on until strong seedlings, then transplant outdoors. Space 60cm apart in deep, fertile soil enriched with compost. Do not pull stems first year. Subsequently pull stems from April onwards. Perennial plant produces for 10+ years.', '02-01', '04-30', NULL, NULL, '09-01', '11-30', '04-01', '06-30'),
('Lettuce', 'Little Gem', 'vegetable', 1500, 'Yorkshire Seeds', 2025, 2029, 'Mini romaine lettuce producing compact heads with tender leaves. Classic variety for home gardeners.', 'https://yorkshire-seeds.co.uk/products/vegetable-lettuce-little-gem-1500-seeds-premium-vegetable-seeds', '7-10 days', '12-18°C', NULL, '20cm', 'Full sun to partial shade', 'Sow direct outdoors or start in trays indoors. Germination 7-10 days. Thin seedlings to 20cm apart. Keep soil moist throughout growing season. Ready to harvest 8-10 weeks after sowing. For continuous supply, sow seeds every 2-3 weeks from spring to early autumn.', '02-01', '03-31', '03-01', '09-30', NULL, NULL, '04-15', '10-31'),
('Onion', 'Spring Onion Long White Ishikura', 'vegetable', 700, 'Yorkshire Seeds', 2025, 2027, 'Bunching onion producing long white stems with mild flavour. Early maturing variety for spring and summer harvest.', 'https://yorkshire-seeds.co.uk/products/spring-onion-seeds-700-seeds-long-white-ishikura-vegetable-seeds', '10-14 days', '15-18°C', NULL, '15-25cm', 'Full sun', 'Sow direct in spring, 1cm deep in rows 15cm apart. Thin seedlings to 10cm. Alternatively sow indoors in late winter and transplant. Germination 10-14 days. Keep well watered. Harvest when stems reach desired thickness, typically 12-16 weeks after sowing. Can be harvested continuously by picking outer stems.', '01-15', '02-28', '02-15', '08-31', NULL, NULL, '04-15', '09-30'),
('Broccoli', 'Green Large Calabrese', 'vegetable', 100, 'Yorkshire Seeds', 2025, 2029, 'Large green broccoli heads on compact plants. Classic calabrese variety with excellent flavour.', 'https://yorkshire-seeds.co.uk/products/green-large-broccoli-calabrese-100x-seeds-vegetable-b310', '7-10 days', '18-21°C', NULL, '60cm', 'Full sun', 'Sow indoors in spring or direct sow in summer. Germination 7-10 days. Thin to 45cm apart. Keep well watered throughout growing season. Harvest main head while tight, secondary heads will develop. Ready to harvest 60-70 days after transplanting.', '02-01', '04-30', '06-01', '07-31', NULL, NULL, '05-01', '09-30'),
('Cabbage', 'Giant Sweet Red Ball', 'vegetable', 100, 'Yorkshire Seeds', 2025, 2029, 'Large round red cabbage with sweet flavour. Simple to grow variety ideal for home gardeners.', 'https://yorkshire-seeds.co.uk/products/giant-sweet-red-ball-cabbage-100x-seeds-simple-to-grow-vegetable-b37', '7-10 days', '18-21°C', NULL, '30-40cm', 'Full sun to partial shade', 'Sow indoors in early spring for summer cabbage, or late spring for autumn/winter harvest. Germination 7-10 days. Transplant seedlings 45cm apart each way. Water regularly and keep weed-free. Harvest when heads are firm, typically 60-90 days after transplanting depending on season.', '02-01', '04-30', NULL, NULL, '04-15', '06-30', '06-01', '11-30'),
('Kale', 'Giant Black Magic British', 'vegetable', 100, 'Yorkshire Seeds', 2025, 2028, 'Large dark purple-black leaves with excellent texture. Borecole kale variety improves flavour after frost.', 'https://yorkshire-seeds.co.uk/products/giant-black-magic-british-kale-100x-seeds-borecole-vegetable-b38', '7-12 days', '15-18°C', NULL, '60-75cm', 'Full sun to partial shade', 'Sow indoors in late spring for autumn/winter harvest. Germination 7-12 days. Transplant when 15cm tall, 45cm apart. Prefers cool weather and improves in flavour after frost. Harvest outer leaves regularly from October through to spring. Can produce for several months.', '04-01', '05-31', NULL, NULL, '06-15', '07-31', '10-01', '03-31'),
('Radish', 'Rainbow Mix', 'vegetable', 1300, 'Yorkshire Seeds', 2025, 2029, 'Fast growing mix of red, purple and yellow radish varieties. Ready to harvest in just 25-30 days.', 'https://yorkshire-seeds.co.uk/products/radish-rainbow-mix-1300x-seeds-fast-growing-red-purple-yellow-vegetable-b115', '3-7 days', '10-20°C', NULL, '5cm', 'Full sun to partial shade', 'Sow direct in shallow drills, 1cm deep, thinning to 5cm apart. Successive sowing every 2 weeks for continuous supply. Germination 3-7 days. Keep soil moist for crisp roots. Ready to harvest 25-30 days after sowing. Pull when marble-sized to avoid woodiness.', NULL, NULL, '02-01', '09-30', NULL, NULL, '03-01', '10-31'),
('Aubergine', 'Moneymaker F1', 'vegetable', 50, 'Yorkshire Seeds', 2025, 2029, 'F1 hybrid aubergine producing prolific dark purple fruits. Reliable heavy cropper suitable for greenhouse or outdoors.', 'https://yorkshire-seeds.co.uk/products/aubergine-moneymaker-f1-50x-seeds-solanum-melongena-vegetable-b103', '7-14 days', '21-25°C', NULL, '60-75cm', 'Greenhouse/Conservatory', 'Sow indoors in early spring in heated propagator at 21-25°C. Germination 7-14 days. Prick out into individual pots. Plant out into greenhouse or warm sheltered spot when 30cm tall. Space 60cm apart. Provide support. Pinch out growing tip to encourage branching. Harvest fruits when young and glossy.', '02-01', '03-31', NULL, NULL, '05-15', '06-30', '07-01', '09-30'),
('Basil', 'Licorice', 'herb', 900, 'Yorkshire Seeds', 2025, 2030, 'Thai basil variety with distinctive licorice/anise flavour. Aromatic herb for Asian cooking.', 'https://yorkshire-seeds.co.uk/products/400x-herb-basil-thai-liquorice-flavour-finest-seeds-herb', '7-10 days', '18-21°C', NULL, '30-45cm', 'Warm sunny location', 'Sow indoors in spring on surface of seed compost, lightly cover. Germination 7-10 days at 18-21°C. Prick out into individual pots. Plant out after last frost in warm sunny spot, 30cm apart. Pinch out flower buds to encourage leaf production. Harvest regularly. Can be grown in containers.', '03-01', '05-31', NULL, NULL, '05-15', '06-30', '06-01', '10-31'),
('Parsley', 'Italian Triple Moss Curled', 'herb', 700, 'Yorkshire Seeds', 2025, 2026, 'Classic curly parsley with finely crinkled leaves. Italian variety with robust flavour.', 'https://yorkshire-seeds.co.uk/products/italian-parsley-triple-moss-curled-700x-seeds-herb', '14-21 days', '15-18°C', NULL, '30cm', 'Full sun to partial shade', 'Soak seed overnight to aid germination. Sow direct outdoors or start indoors in late winter. Germination 14-21 days (slow). Thin to 20cm apart. Can be slow to establish. Harvest outer leaves regularly once plant is well established. Biennial producing mainly leaves in first year.', '01-01', '02-28', '03-01', '08-31', NULL, NULL, '05-01', '10-31'),
('Dill', 'Anethum Graveolens', 'herb', 1000, 'Yorkshire Seeds', 2025, 2026, 'Classic dill herb with feathery blue-green foliage and aromatic seeds. Essential for pickling.', 'https://yorkshire-seeds.co.uk/products/herb-dill-anethum-graveolens-1000-seeds-finest-seeds', '7-14 days', '15-18°C', NULL, '60-90cm', 'Full sun', 'Sow direct outdoors in spring, barely cover seeds. Germination 7-14 days. Thin to 20cm apart. Prefers well-drained soil. Water moderately. Can self-seed for next season. Harvest leaves throughout growing season. Leave some plants to flower for seed heads for pickling.', NULL, NULL, '02-15', '06-30', NULL, NULL, '05-01', '09-30'),
('Sage', 'Broad Leaved Salvia Officinalis', 'herb', 50, 'Yorkshire Seeds', 2025, 2027, 'Broad-leaved sage variety with excellent flavour. Perennial herb producing for many years.', 'https://yorkshire-seeds.co.uk/products/50x-sage-broad-leaved-salvia-officinalis-seeds-herb', '10-14 days', '15-20°C', NULL, '60cm', 'Full sun', 'Sow indoors in spring on surface of seed compost, lightly cover. Germination 10-14 days. Prick out into individual pots. Plant out after frost 60cm apart in well-drained soil. Drought tolerant once established. Perennial producing foliage for many years. Harvest leaves as required.', '02-01', '03-31', NULL, NULL, '05-01', '06-30', '05-01', '10-31'),
('Rocket', 'Salad Cultivated', 'vegetable', 12000, 'Yorkshire Seeds', 2025, 2029, 'Cultivated rocket with peppery flavour. Prolific producer with plenty of seeds for repeated sowings.', 'https://yorkshire-seeds.co.uk/products/wild-rocket-salad-seeds-italian-arugula-sylvetta-3000-seeds', '5-10 days', '12-18°C', NULL, '20-30cm', 'Full sun to partial shade', 'Sow direct outdoors in spring and continue sowing every 2-3 weeks for continuous supply. Germination 5-10 days. Thin seedlings to 15cm apart. Keep moist but not waterlogged. Ready to harvest in 30-40 days. Cut leaves when young and tender. Can be harvested continuously.', NULL, NULL, '02-01', '10-31', NULL, NULL, '03-15', '11-30'),
('Thyme', 'Purple Creeping', 'herb', 900, 'Yorkshire Seeds', 2025, 2027, 'Creeping thyme with purple-tinged foliage. Ground cover variety with typical thyme flavour.', 'https://yorkshire-seeds.co.uk/products/herb-thyme-purple-creeping-900-seeds-premium-finest-seeds', '10-14 days', '15-18°C', NULL, '10-15cm', 'Full sun', 'Sow indoors in spring on surface of seed compost, lightly cover. Germination 10-14 days. Prick out into individual pots. Plant out 30cm apart in well-drained soil. Creeping variety works well as ground cover. Drought tolerant once established. Perennial producing foliage for many years. Harvest stems as required for culinary use.', '02-01', '03-31', NULL, NULL, '05-01', '06-30', '05-01', '10-31'),
('Lychnis', 'Arkwright S Campion', 'flower', 250, 'Yorkshire Seeds', 2025, 2027, 'Vibrant rose-pink flowers on compact plants. Perennial campion variety with long flowering period.', 'https://yorkshire-seeds.co.uk/products/lychnis-arkwright-s-campion-250x-seeds-lychnis-flower', '7-14 days', '15-20°C', NULL, '30-40cm', 'Full sun', 'Sow indoors in spring on surface of seed compost, lightly cover. Germination 7-14 days. Prick out into individual pots. Plant out after last frost, 30cm apart in well-drained soil. Prefers sunny position. Deadhead spent flowers to encourage more blooms. Perennial producing flowers for many years.', '02-01', '04-30', NULL, NULL, '05-01', '06-30', '05-01', '08-31'),
('California Poppy', 'Red California Poppy Chief', 'flower', 2100, 'Yorkshire Seeds', 2025, 2027, 'Eschscholzia californica with brilliant red flowers. Annual poppy with delicate tissue-paper petals.', 'https://yorkshire-seeds.co.uk/products/red-california-poppy-chief-eschscholzia-californica-2100x-flower', '7-10 days', '15-18°C', NULL, '30-45cm', 'Full sun', 'Sow direct outdoors in spring, barely cover seeds. Germination 7-10 days. Thin to 20cm apart. Prefers poor to moderately fertile soil. Drought tolerant once established. Self-seeds readily. Flowers close at night and on cloudy days. Deadhead regularly for continuous flowering.', NULL, NULL, '03-01', '05-31', NULL, NULL, '04-01', '06-30'),
('Pak Choi', 'Giant White Stem Canton', 'vegetable', 100, 'Yorkshire Seeds', 2025, 2028, 'Chinese cabbage with white stems and tender green leaves. Fast-growing brassica ready in 6-8 weeks.', 'https://yorkshire-seeds.co.uk/products/giant-pak-choi-chinese-cabbage-white-stem-canton-100x-seeds-vegetable', '7-10 days', '15-20°C', NULL, '30cm', 'Full sun to partial shade', 'Sow direct or start indoors in spring. Germination 7-10 days. Thin to 25-30cm apart. Keep well watered for tender leaves. Can be harvested whole or pick outer leaves. Early maturing variety ready 6-8 weeks after sowing. Succession sow for continuous supply.', '02-15', '03-31', '03-01', '07-31', NULL, NULL, '04-01', '08-31'),
('Leek', 'Giant Winter Hardy', 'vegetable', 350, 'Yorkshire Seeds', 2025, 2026, 'Winter hardy leek producing large white stems. Extended harvest season from autumn through to spring.', 'https://yorkshire-seeds.co.uk/products/leek-giant-winter-seeds-350x-seeds-vegetable-seeds-premium-seeds', '12-18 days', '15-18°C', NULL, '30-40cm', 'Full sun to partial shade', 'Sow indoors in late winter into seed compost. Germination 12-18 days. Transplant seedlings into garden when 15-20cm tall, 15cm apart with 30cm between rows. Earth up regularly to blanch stems. Harvest from October through to March by lifting from ground.', '01-15', '03-15', NULL, NULL, '04-01', '06-30', '10-01', '03-31'),
('Shallot', 'Zebrune', 'vegetable', 500, 'Yorkshire Seeds', 2025, 2026, 'Red and white striped bulbs with excellent flavour. Prolific producer dividing into multiple bulbs.', 'https://yorkshire-seeds.co.uk/products/shallot-zebrune-500x-seeds-vegetable', '7-14 days', '16-21°C', NULL, '10-15cm', 'Full sun', 'Sow indoors in late winter into seed compost. Germination 7-14 days. Transplant seedlings into garden when 10-15cm tall, 15cm apart in rows 30cm apart. Bulb division starts in summer. Harvest when foliage yellows, typically July/August. Cure in warm dry place before storing.', '01-15', '02-28', NULL, NULL, '03-15', '04-30', '07-01', '08-31'),
('Carrot', 'Touchon', 'vegetable', 4100, 'Yorkshire Seeds', 2025, 2027, 'Nantes type carrot with slender cylindrical roots and excellent sweet flavour. Reliable heavy cropper.', 'https://yorkshire-seeds.co.uk/products/4100x-carrot-touchon-seeds-vegetable-b104', NULL, NULL, NULL, NULL, NULL, 'Sow direct in well-prepared fine seedbed, 1.5-2cm deep in rows 25-30cm apart. Thin to 7-10cm when large enough. Keep weed-free and watered. Succession sow every 2 weeks for extended harvest. Ready to harvest from June onwards. Bold shoulders and good colour.', NULL, NULL, '03-01', '08-31', NULL, NULL, '06-01', '10-31'),
('Soapwort', 'Pink Soapwort Saponaria Ocymoides', 'flower', 900, 'Yorkshire Seeds', 2025, 2027, 'Rock garden perennial with pink flowers. Trailing habit suitable for alpine troughs and borders.', 'https://yorkshire-seeds.co.uk/products/900x-pink-soapwort-saponaria-ocymoides-seeds-rock-flower-perennial-d1612', '7-14 days', '15-18°C', NULL, '15-20cm', 'Full sun to partial shade', 'Sow indoors in spring on well-draining seed compost, lightly cover. Germination 7-14 days. Prick out into individual pots. Plant out in rock garden or border 30cm apart. Drought tolerant once established. Trailing perennial producing pink flowers for many years.', '02-01', '04-30', NULL, NULL, '05-01', '06-30', '05-01', '07-31'),
('Forget Me Not', 'Rose Pink Myosotis Alpestris', 'flower', 1200, 'Yorkshire Seeds', 2025, 2027, 'Alpine forget-me-not with rose-pink delicate flowers. Biennial or short-lived perennial for borders.', 'https://yorkshire-seeds.co.uk/products/1200x-forget-me-not-rose-pink-myosotis-alpestris-seeds-flower-b1015', '7-14 days', '12-18°C', NULL, '20-30cm', 'Full sun to partial shade', 'Sow indoors in late winter on surface of seed compost, lightly press in. Germination 7-14 days. Prick out into trays. Harden off and plant out 20cm apart. Self-seeds readily. Biennial producing flowers in second year. Early flowering starts from mid-spring.', '01-15', '02-28', NULL, NULL, '04-01', '05-31', '05-01', '06-30'),
('Verbena', 'Tenuisecta Violet Moss', 'flower', 350, 'Yorkshire Seeds', 2025, 2027, 'Annual verbena with fine feathery foliage and purple flowers. Dainty compact plants ideal for containers.', 'https://yorkshire-seeds.co.uk/products/350x-verbena-tenuisecta-annual-flower-seeds-violet-moss-b512', '7-14 days', '18-21°C', NULL, '20-30cm', 'Full sun', 'Sow indoors in spring on seed compost, lightly cover. Germination 7-14 days at 18-21°C. Prick out into trays. Harden off and plant out after last frost, 20-30cm apart. Drought tolerant once established. Deadhead regularly for continuous flowering. Ideal for bedding and containers.', '02-15', '03-31', NULL, NULL, '05-01', '05-31', '06-01', '09-30'),
('Parsley', 'Giant Italian', 'herb', 4000, 'Yorkshire Seeds', 2025, 2026, 'Large-leaved Italian flat parsley with robust flavour. Prolific producer with 4000 seeds for multiple sowings.', 'https://yorkshire-seeds.co.uk/products/4000x-parsley-giant-italian-seeds-petroselinum-grow-all-year-round-herb-b117', '14-21 days', '15-18°C', NULL, '30cm', 'Full sun to partial shade', 'Soak seed overnight to aid germination. Sow direct outdoors or start indoors in late winter. Germination 14-21 days (slow). Thin to 20cm apart. Can be slow to establish. Succession sow for continuous supply. Harvest outer stems regularly once plant established. Biennial producing mainly leaves in first year.', '01-01', '02-28', '03-01', '09-30', NULL, NULL, '05-01', '10-31'),
('Chives', 'Common Chives', 'herb', 200, 'Yorkshire Seeds', 2025, 2026, 'Fine-leafed herb with delicate onion flavour. Early spring perennial producing throughout season.', 'https://yorkshire-seeds.co.uk/products/chives-seeds-herb-200-seeds-finest', '7-14 days', '15-20°C', NULL, '20-30cm', 'Full sun to partial shade', 'Sow indoors in late winter on surface of seed compost, lightly press in. Germination 7-14 days. Prick out into individual pots. Plant out in clumps 25cm apart in moist soil. Perennial producing fine foliage throughout year. Harvest leaves regularly as required. Purple flowers in late spring attract insects.', '01-15', '02-28', NULL, NULL, '03-01', '05-31', '05-01', '10-31'),
('Lemongrass', 'Cymbopogon Flexuosus', 'herb', 350, 'Yorkshire Seeds', 2025, 2026, 'Tropical aromatic herb with lemony flavour. Popular in Asian cuisine and for herbal teas.', 'https://yorkshire-seeds.co.uk/products/lemongrass-cymbopogon-flexuous-herb-350x-seeds-aromatic-b520', '14-21 days', '21-25°C', NULL, '60-90cm', 'Warm sunny location', 'Sow indoors in spring on moist seed compost, lightly cover. Germination 14-21 days at 21-25°C (slow). Prick out into individual pots. Grow on in warm location. Plant out after all frost risk in warm sunny spot. Alternatively grow in containers indoors. Harvest stems as required for culinary use.', '02-15', '04-30', NULL, NULL, '05-15', '06-30', '06-01', '10-31'),
('Peppermint', 'Mentha Piperita', 'herb', 500, 'Yorkshire Seeds', 2025, 2026, 'Culinary and medicinal mint with strong peppermint flavour. Vigorous perennial spreading readily.', 'https://yorkshire-seeds.co.uk/products/peppermint-mentha-piperita-500x-seeds-herb', '7-14 days', '15-20°C', NULL, '60cm', 'Full sun to partial shade', 'Sow indoors in spring on surface of seed compost, lightly press in. Germination 7-14 days. Prick out into individual pots. Plant out in clumps 45cm apart. Vigorous grower may need containment. Prefers moist soil. Perennial producing foliage throughout year. Harvest leaves regularly. Prone to rust.', '02-01', '04-30', NULL, NULL, '04-01', '06-30', '05-01', '10-31'),
('Oregano', 'Greek Oregano', 'herb', 700, 'Yorkshire Seeds', 2025, 2026, 'Culinary oregano with excellent flavour for Mediterranean cooking. Compact perennial herb.', 'https://yorkshire-seeds.co.uk/products/oregano-seeds-herb-700x-seeds-finest', '7-14 days', '15-20°C', NULL, '30-40cm', 'Full sun', 'Sow indoors in spring on surface of seed compost, lightly cover. Germination 7-14 days at 15-20°C. Prick out into individual pots. Plant out after last frost 30cm apart in well-drained soil. Drought tolerant once established. Perennial producing foliage for many years. Harvest leaves as required for drying or fresh use.', '02-15', '03-31', NULL, NULL, '05-01', '06-30', '06-01', '10-31'),
('Thyme', 'Garden Thyme', 'herb', 350, 'Yorkshire Seeds', 2025, 2026, 'Common thyme variety with fine foliage and typical culinary thyme flavour. Hardy perennial ground cover.', 'https://yorkshire-seeds.co.uk/products/thyme-seeds-herb-350-seeds-finest', '10-14 days', '15-18°C', NULL, '20-30cm', 'Full sun', 'Sow indoors in spring on surface of seed compost, lightly cover. Germination 10-14 days at 15-18°C. Prick out into individual pots. Plant out 30cm apart in well-drained soil. Drought tolerant when established. Compact growth suitable as border edging. Perennial producing foliage for many years. Harvest stems as required for culinary use.', '02-15', '03-31', NULL, NULL, '05-01', '06-30', '06-01', '10-31'),
('Spinach', 'Giant Winter Hardy', 'vegetable', 300, 'Yorkshire Seeds', 2025, 2027, 'Winter hardy spinach variety producing large tender leaves. Excellent for autumn and winter harvesting.', 'https://yorkshire-seeds.co.uk/products/giant-winter-spinach-seeds-300x-hardy-spinach-vegetable', '7-14 days', '12-18°C', NULL, '20-25cm', 'Full sun to partial shade', 'Sow direct outdoors in late summer for autumn/winter harvest. Germination 7-14 days. Thin seedlings to 15cm apart. Keep soil moist. Can be harvested continuously by picking outer leaves or whole plants. Frost hardy, improves in flavour after frost. Successive sowings July-August for extended harvest.', NULL, NULL, '07-01', '09-30', NULL, NULL, '09-01', '03-31'),
('Spinach', 'Giant Winter Baby Leaf Year Round', 'vegetable', 100, 'Yorkshire Seeds', 2025, 2027, 'Winter spinach baby leaf variety for year-round cultivation. Fast maturing tender leaves for salads.', 'https://yorkshire-seeds.co.uk/products/giant-winter-spinach-baby-leaf-year-round-100x-seeds-vegetable', '7-14 days', '12-18°C', NULL, '15-20cm', 'Full sun to partial shade', 'Sow direct in shallow drills outdoors. Germination 7-14 days. Thin to 10cm apart for baby leaf production. Keep soil consistently moist. Harvest when leaves reach tender stage approximately 30-40 days after sowing. Succession sow every 2-3 weeks for continuous supply.', '02-01', '09-30', '02-01', '09-30', NULL, NULL, '03-15', '10-31'),
('Courgette', 'Atena Polka F1', 'vegetable', 10, 'Yorkshire Seeds', 2025, 2029, 'F1 hybrid courgette producing prolific yellow and green striped fruits. Early maturing variety suitable for pots and borders.', 'https://yorkshire-seeds.co.uk/products/atena-polka-courgette-f1-10x-seeds-vegetable', '6-10 days', '20-25°C', NULL, '45-60cm', 'Full sun', 'Sow indoors in spring in pots, 1-2 seeds per pot. Germination 6-10 days at 20-25°C. Thin to strongest seedling. Plant out after last frost with careful pot spacing 60cm apart in warm spot. Keep soil moist but not waterlogged. Feed weekly once flowering starts. Harvest fruits regularly when 15-20cm for continuous production.', '03-01', '04-30', NULL, NULL, '05-15', '06-30', '06-01', '08-31'),
('Lettuce', 'Lollo Rosso', 'vegetable', 1100, 'Yorkshire Seeds', 2025, 2029, 'Red loose-leaf lettuce with frilly deeply lobed leaves. Attractive and tender variety for salads.', 'https://yorkshire-seeds.co.uk/products/lettuce-lollo-rosso-leaf-1100x-seeds-vegetable-b118', '7-10 days', '12-18°C', NULL, '25-30cm', 'Full sun to partial shade', 'Sow direct outdoors or start indoors in trays. Germination 7-10 days. Thin seedlings to 20-25cm apart for full-sized plants or 10cm for baby leaves. Keep soil moist. Ready to harvest 8-10 weeks after sowing. Harvest outer leaves continuously or cut whole head. Succession sow every 2-3 weeks for continuous supply.', '02-01', '03-31', '03-01', '09-30', NULL, NULL, '04-15', '10-31'),
('Lettuce', 'Baby Leaf Mixed', 'vegetable', 950, 'Yorkshire Seeds', 2025, 2029, 'Mixed salad leaf blend for cut-and-grow-again harvesting. Easy to cultivate blend of tender leaves.', 'https://yorkshire-seeds.co.uk/products/lettuce-seed-babyleaf-mixed-leaves-950-seeds-easy-cut-and-grow-again-salad', '5-10 days', '12-18°C', NULL, '15-20cm', 'Full sun to partial shade', 'Sow direct in shallow drills or broadcast over prepared soil. Germination 5-10 days. Do not thin - cut whole crop when leaves reach 10-15cm height. Regrows for multiple harvests. Keep soil moist. Succession sow every 2-3 weeks for continuous harvest. Ideal for containers and small spaces.', '02-01', '09-30', '02-01', '09-30', NULL, NULL, '03-15', '10-31'),
('Lettuce', 'All Year Round Butterhead', 'vegetable', 600, 'Yorkshire Seeds', 2025, 2029, 'Heritage butterhead lettuce suitable for cultivation throughout year. Reliable variety with soft buttery leaves.', 'https://yorkshire-seeds.co.uk/products/lettuce-all-year-round-seeds-x-600-butterhead-heritage-vegetable-seeds', '7-10 days', '12-18°C', NULL, '20-25cm', 'Full sun to partial shade', 'Sow indoors in late winter for spring crop or direct outdoors spring-autumn. Germination 7-10 days. Thin to 20-25cm apart. Keep soil consistently moist. Ready to harvest 60-70 days after sowing. Cut heads when firm and full. Can be sown successively for year-round supply.', '01-15', '03-31', '03-01', '09-30', NULL, NULL, '04-15', '10-31'),
('Lettuce', 'Salad Bowl Green', 'vegetable', 1500, 'Yorkshire Seeds', 2025, 2029, 'Green loose-leaf salad bowl lettuce with deeply lobed tender leaves. Prolific producer ideal for repeated harvesting.', 'https://yorkshire-seeds.co.uk/products/organic-lettuce-salad-bowl-green-1500x-seeds-lettuce', '7-10 days', '12-18°C', NULL, '25-30cm', 'Full sun to partial shade', 'Sow direct outdoors or start indoors in trays. Germination 7-10 days. Thin to 20cm apart for full plants or 10cm for baby leaves. Keep consistently moist to prevent bolting. Harvest outer leaves continuously starting 6-8 weeks after sowing. Multiple harvests from single plant. Succession sow every 2-3 weeks.');
